using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using System.Text.Encodings.Web;
using System.Text.RegularExpressions;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Html;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace MyStore.Web.Controllers
{
    public class ProductController : Controller
    {
        private readonly AppDbContext _db;

        public ProductController(AppDbContext db)
        {
            _db = db;
        }

        [HttpGet("/products/{id:int}")]
        public async Task<IActionResult> Details(int id)
        {
            var product = await _db.Products
                .AsNoTracking()
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
                return NotFound();

            var reviews = await _db.Reviews
                .AsNoTracking()
                .Where(r => r.ProductId == id && r.IsApproved)
                .OrderByDescending(r => r.CreatedUtc)
                .Select(r => new ReviewViewModel
                {
                    Id = r.Id,
                    AuthorName = r.AuthorName,
                    Rating = r.Rating,
                    CreatedUtc = r.CreatedUtc,
                    BodyHtml = ReviewFormatting.ToSafeHtml(r.Body)
                })
                .ToListAsync();

            var vm = new ProductDetailsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews
            };

            return View("Details", vm);
        }
    }

    public sealed class ProductDetailsViewModel
    {
        public int ProductId { get; set; }
        public string ProductName { get; set; } = "";
        public List<ReviewViewModel> Reviews { get; set; } = new();
    }

    public sealed class ReviewViewModel
    {
        public int Id { get; set; }
        public string AuthorName { get; set; } = "";
        public int Rating { get; set; }
        public DateTime CreatedUtc { get; set; }
        public IHtmlContent BodyHtml { get; set; } = HtmlString.Empty;
    }

    public static class ReviewFormatting
    {
        private static readonly Regex Bold = new Regex(@"\*\*(.+?)\*\*", RegexOptions.Compiled | RegexOptions.Singleline);
        private static readonly Regex Italic = new Regex(@"\*(.+?)\*", RegexOptions.Compiled | RegexOptions.Singleline);

        public static IHtmlContent ToSafeHtml(string? input)
        {
            if (string.IsNullOrWhiteSpace(input))
                return HtmlString.Empty;

            var encoded = HtmlEncoder.Default.Encode(input);

            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n").Replace("\n", "<br />\n");

            encoded = Bold.Replace(encoded, "<strong>$1</strong>");
            encoded = Italic.Replace(encoded, "<em>$1</em>");

            return new HtmlString(encoded);
        }
    }

    public class AppDbContext : DbContext
    {
        public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

        public DbSet<Product> Products => Set<Product>();
        public DbSet<Review> Reviews => Set<Review>();
    }

    public class Product
    {
        public int Id { get; set; }

        [Required, StringLength(200)]
        public string Name { get; set; } = "";
    }

    public class Review
    {
        public int Id { get; set; }

        [Required]
        public int ProductId { get; set; }

        [Required, StringLength(100)]
        public string AuthorName { get; set; } = "";

        [Range(1, 5)]
        public int Rating { get; set; }

        [Required, StringLength(4000)]
        public string Body { get; set; } = "";

        public bool IsApproved { get; set; } = true;

        public DateTime CreatedUtc { get; set; } = DateTime.UtcNow;

        public Product? Product { get; set; }
    }
}

@model MyStore.Web.Controllers.ProductDetailsViewModel
@{
    ViewData["Title"] = Model.ProductName;
}

<h1>@Model.ProductName</h1>

<section aria-label="Reviews">
    <h2>Reviews</h2>

    @if (Model.Reviews == null || Model.Reviews.Count == 0)
    {
        <p>No reviews yet.</p>
    }
    else
    {
        <ul class="reviews">
            @foreach (var r in Model.Reviews)
            {
                <li class="review">
                    <div class="review-meta">
                        <strong>@r.AuthorName</strong>
                        <span> — </span>
                        <span>@r.CreatedUtc.ToLocalTime().ToString("yyyy-MM-dd")</span>
                        <span> — </span>
                        <span>@r.Rating/5</span>
                    </div>
                    <div class="review-body">
                        @r.BodyHtml
                    </div>
                </li>
            }
        </ul>
    }
</section>